import {
  evaluateHealthScoreChange,
  getAlertHistory,
  resetState,
  type HealthScoreChangeAlert,
} from "../services/healthScoreChangeAlertService";
import type { StrategyHealthScore } from "../services/strategyHealthService";

function makeScore(overrides: Partial<StrategyHealthScore> = {}): StrategyHealthScore {
  return {
    strategyId: "test-strategy",
    strategyName: "Test Strategy",
    overallScore: 80,
    metrics: {
      contractSafety: 0.9,
      dataFreshness: 0.85,
      providerUptime: 0.95,
      liquidityConditions: 0.8,
      executionOutcomes: 0.9,
      volatilityIndex: 0.3,
      errorRate: 0.02,
      latency: 200,
    },
    status: "healthy",
    signals: [],
    lastUpdated: new Date().toISOString(),
    trend: "stable",
    recommendations: [],
    ...overrides,
  };
}

describe("healthScoreChangeAlertService", () => {
  beforeEach(() => {
    resetState();
  });

  describe("evaluateHealthScoreChange", () => {
    it("returns null on first evaluation (no baseline)", () => {
      const alert = evaluateHealthScoreChange(makeScore());
      expect(alert).toBeNull();
    });

    it("returns null when score change is below threshold", () => {
      evaluateHealthScoreChange(makeScore({ overallScore: 80 }));
      const alert = evaluateHealthScoreChange(makeScore({ overallScore: 85 }));
      expect(alert).toBeNull();
    });

    it("returns alert when score drops significantly", () => {
      evaluateHealthScoreChange(makeScore({ overallScore: 85 }));
      const alert = evaluateHealthScoreChange(
        makeScore({
          overallScore: 70,
          status: "degraded",
        }),
      );

      expect(alert).not.toBeNull();
      expect(alert!.previousScore).toBe(85);
      expect(alert!.currentScore).toBe(70);
      expect(alert!.scoreDelta).toBe(-15);
      expect(alert!.previousStatus).toBe("healthy");
      expect(alert!.currentStatus).toBe("degraded");
    });

    it("returns alert when score improves significantly", () => {
      evaluateHealthScoreChange(makeScore({ overallScore: 50, status: "critical" }));
      const alert = evaluateHealthScoreChange(
        makeScore({
          overallScore: 70,
          status: "degraded",
        }),
      );

      expect(alert).not.toBeNull();
      expect(alert!.scoreDelta).toBe(20);
    });

    it("includes changed factors in the alert", () => {
      evaluateHealthScoreChange(
        makeScore({
          overallScore: 80,
          metrics: {
            contractSafety: 0.9,
            dataFreshness: 0.85,
            providerUptime: 0.95,
            liquidityConditions: 0.8,
            executionOutcomes: 0.9,
            volatilityIndex: 0.3,
            errorRate: 0.02,
            latency: 200,
          },
        }),
      );

      const alert = evaluateHealthScoreChange(
        makeScore({
          overallScore: 65,
          metrics: {
            contractSafety: 0.5, // Significant drop
            dataFreshness: 0.85,
            providerUptime: 0.95,
            liquidityConditions: 0.4, // Significant drop
            executionOutcomes: 0.9,
            volatilityIndex: 0.3,
            errorRate: 0.02,
            latency: 200,
          },
        }),
      );

      expect(alert).not.toBeNull();
      expect(alert!.changedFactors.length).toBeGreaterThan(0);

      const contractFactor = alert!.changedFactors.find(
        (f) => f.metric === "contractSafety",
      );
      expect(contractFactor).toBeDefined();
      expect(contractFactor!.significant).toBe(true);
      expect(contractFactor!.previousValue).toBe(0.9);
      expect(contractFactor!.currentValue).toBe(0.5);
    });

    it("respects cooldown period", () => {
      // First evaluation
      evaluateHealthScoreChange(makeScore({ overallScore: 85 }));

      // First significant change - should alert
      const alert1 = evaluateHealthScoreChange(makeScore({ overallScore: 65 }));
      expect(alert1).not.toBeNull();

      // Second significant change within cooldown - should not alert
      const alert2 = evaluateHealthScoreChange(makeScore({ overallScore: 45 }));
      expect(alert2).toBeNull();
    });
  });

  describe("getAlertHistory", () => {
    it("returns empty history initially", () => {
      expect(getAlertHistory()).toHaveLength(0);
    });

    it("stores alerts in history", () => {
      evaluateHealthScoreChange(makeScore({ overallScore: 85 }));
      evaluateHealthScoreChange(makeScore({ overallScore: 65 }));

      const history = getAlertHistory();
      expect(history.length).toBeGreaterThanOrEqual(1);
      expect(history[0].previousScore).toBe(85);
      expect(history[0].currentScore).toBe(65);
    });

    it("respects limit parameter", () => {
      // Generate multiple alerts (different strategies to avoid cooldown)
      for (let i = 0; i < 5; i++) {
        evaluateHealthScoreChange(
          makeScore({ strategyId: `s${i}`, overallScore: 85 }),
        );
        evaluateHealthScoreChange(
          makeScore({ strategyId: `s${i}`, overallScore: 65 }),
        );
      }

      const history = getAlertHistory(3);
      expect(history).toHaveLength(3);
    });
  });

  describe("resetState", () => {
    it("clears all state", () => {
      evaluateHealthScoreChange(makeScore({ overallScore: 85 }));
      evaluateHealthScoreChange(makeScore({ overallScore: 65 }));

      resetState();

      // After reset, first evaluation should return null (no baseline)
      const alert = evaluateHealthScoreChange(makeScore({ overallScore: 50 }));
      expect(alert).toBeNull();
      expect(getAlertHistory()).toHaveLength(0);
    });
  });
});

import {
  YieldReliabilityEngine,
  formatReliabilityScore,
  isProviderReliable,
  getWeightedProviderSelection,
  detectAnomalies,
} from "../services/yieldReliabilityService";

describe("YieldReliabilityEngine", () => {
  let engine: YieldReliabilityEngine;

  beforeEach(() => {
    engine = new YieldReliabilityEngine();
  });

  describe("calculateReliabilityScore", () => {
    it("returns high reliability for a healthy provider", async () => {
      const result = await engine.calculateReliabilityScore(
        "blend_api",
        "Blend Protocol",
        "api",
      );

      expect(result.reliabilityScore).toBeGreaterThanOrEqual(0);
      expect(result.reliabilityScore).toBeLessThanOrEqual(100);
      expect(["high", "medium", "low", "unreliable"]).toContain(result.status);
      expect(result.providerId).toBe("blend_api");
      expect(result.providerName).toBe("Blend Protocol");
      expect(["improving", "stable", "declining"]).toContain(result.trend);
    });

    it("returns consistent structure for all known providers", async () => {
      const providers = [
        { id: "blend_api", name: "Blend Protocol", source: "api" },
        { id: "soroswap_api", name: "Soroswap", source: "api" },
        { id: "defindex_api", name: "DeFindex", source: "api" },
      ];

      const results = await engine.getReliabilityScores(providers);

      expect(results).toHaveLength(3);
      for (const result of results) {
        expect(result).toHaveProperty("reliabilityScore");
        expect(result).toHaveProperty("metrics");
        expect(result).toHaveProperty("signals");
        expect(result).toHaveProperty("status");
        expect(result).toHaveProperty("trend");
        expect(result).toHaveProperty("recommendations");
        expect(result).toHaveProperty("failoverPriority");
        expect(result).toHaveProperty("weightInRecommendations");
      }
    });

    it("returns metrics with valid ranges", async () => {
      const result = await engine.calculateReliabilityScore(
        "test_provider",
        "Test",
        "api",
      );

      expect(result.metrics.freshness).toBeGreaterThanOrEqual(0);
      expect(result.metrics.freshness).toBeLessThanOrEqual(1);
      expect(result.metrics.consistency).toBeGreaterThanOrEqual(0);
      expect(result.metrics.consistency).toBeLessThanOrEqual(1);
      expect(result.metrics.historicalUptime).toBeGreaterThanOrEqual(0);
      expect(result.metrics.historicalUptime).toBeLessThanOrEqual(1);
      expect(result.metrics.errorRate).toBeGreaterThanOrEqual(0);
      expect(result.metrics.errorRate).toBeLessThanOrEqual(1);
      expect(result.metrics.coverage).toBeGreaterThanOrEqual(0);
      expect(result.metrics.coverage).toBeLessThanOrEqual(1);
    });
  });

  describe("status thresholds", () => {
    it("classifies status based on score thresholds", async () => {
      const result = await engine.calculateReliabilityScore(
        "test_provider",
        "Test",
        "api",
      );

      if (result.reliabilityScore >= 85) {
        expect(result.status).toBe("high");
      } else if (result.reliabilityScore >= 70) {
        expect(result.status).toBe("medium");
      } else if (result.reliabilityScore >= 50) {
        expect(result.status).toBe("low");
      } else {
        expect(result.status).toBe("unreliable");
      }
    });
  });

  describe("compareProviders", () => {
    it("ranks providers by multiple criteria", async () => {
      const providers = [
        { id: "blend_api", name: "Blend", source: "api" },
        { id: "soroswap_api", name: "Soroswap", source: "api" },
        { id: "defindex_api", name: "DeFindex", source: "api" },
      ];

      const comparisons = await engine.compareProviders(providers);

      expect(comparisons).toHaveLength(3);
      for (const comp of comparisons) {
        expect(comp.accuracyRank).toBeGreaterThanOrEqual(1);
        expect(comp.speedRank).toBeGreaterThanOrEqual(1);
        expect(comp.uptimeRank).toBeGreaterThanOrEqual(1);
        expect(comp.overallRank).toBeGreaterThanOrEqual(1);
      }
    });
  });

  describe("getProviderUptimeReport", () => {
    it("returns default report for unknown provider", () => {
      const report = engine.getProviderUptimeReport("unknown", "Unknown");

      expect(report.uptimePct).toBe(100);
      expect(report.downtimePct).toBe(0);
      expect(report.sampleCount).toBe(0);
      expect(report.recentOutages).toHaveLength(0);
    });
  });

  describe("config updates", () => {
    it("allows updating configuration", () => {
      engine.updateConfig({ scoreUpdateIntervalMinutes: 20 });
      const config = engine.getConfig();
      expect(config.scoreUpdateIntervalMinutes).toBe(20);
    });

    it("allows clearing cache for specific provider", () => {
      expect(() => engine.clearCache("blend_api")).not.toThrow();
    });

    it("allows clearing all cache", () => {
      expect(() => engine.clearCache()).not.toThrow();
    });
  });
});

describe("formatReliabilityScore", () => {
  it("rounds metrics to reasonable precision", async () => {
    const engine = new YieldReliabilityEngine();
    const raw = await engine.calculateReliabilityScore("test", "Test", "api");
    const formatted = formatReliabilityScore(raw);

    expect(Number.isInteger(formatted.reliabilityScore)).toBe(true);
    expect(formatted.metrics.freshness.toString().split(".")[1]?.length ?? 0).toBeLessThanOrEqual(2);
    expect(formatted.metrics.errorRate.toString().split(".")[1]?.length ?? 0).toBeLessThanOrEqual(4);
  });
});

describe("isProviderReliable", () => {
  it("returns true for high-reliability provider", () => {
    const provider = {
      providerId: "test",
      providerName: "Test",
      dataSource: "api",
      reliabilityScore: 90,
      metrics: {
        freshness: 0.95,
        consistency: 0.9,
        historicalUptime: 0.99,
        anomalyRate: 0.05,
        latency: 200,
        errorRate: 0.02,
        coverage: 0.95,
        accuracy: 0.98,
      },
      signals: {} as never,
      status: "high" as const,
      lastUpdated: new Date().toISOString(),
      trend: "stable" as const,
      recommendations: [],
      failoverPriority: 10,
      weightInRecommendations: 1.0,
    };

    expect(isProviderReliable(provider)).toBe(true);
  });

  it("returns false for unreliable provider", () => {
    const provider = {
      providerId: "test",
      providerName: "Test",
      dataSource: "api",
      reliabilityScore: 30,
      metrics: {
        freshness: 0.3,
        consistency: 0.2,
        historicalUptime: 0.5,
        anomalyRate: 0.8,
        latency: 2000,
        errorRate: 0.3,
        coverage: 0.4,
        accuracy: 0.5,
      },
      signals: {} as never,
      status: "unreliable" as const,
      lastUpdated: new Date().toISOString(),
      trend: "declining" as const,
      recommendations: ["Disable provider"],
      failoverPriority: 999,
      weightInRecommendations: 0,
    };

    expect(isProviderReliable(provider)).toBe(false);
  });
});

describe("detectAnomalies", () => {
  it("detects anomaly when value is far from historical mean", () => {
    const historical = [10, 10, 10, 10, 10, 10, 10, 10, 10, 10, 10, 10];
    expect(detectAnomalies(50, historical, 0.1)).toBe(true);
  });

  it("does not flag normal variation", () => {
    const historical = [10, 10.1, 9.9, 10, 10.2, 9.8, 10, 10.1, 9.9, 10, 10.1, 9.9];
    expect(detectAnomalies(10.5, historical, 0.1)).toBe(false);
  });

  it("returns false with insufficient data", () => {
    expect(detectAnomalies(100, [1, 2, 3])).toBe(false);
  });
});

/**
 * Fragmentation API Router
 * GET /api/liquidity/fragmentation - Returns current liquidity fragmentation metrics
 * 
 * Requirements: 3.1, 3.2, 3.3, 3.5
 */

import { Router, type Request, type Response } from 'express';

// Import types from backend/keepers (will be shared)
interface FragmentationMetrics {
  fragmentationScore: number;
  hhi: number;
  effectiveProtocolCount: number;
  multiProtocolRoutingPct: number;
  executionQualityScore: number;
  materialImpact: boolean;
  category: 'Low' | 'Medium' | 'High';
  categoryDescription: string;
  protocolBreakdown: ProtocolContribution[];
  dataCompleteness: DataCompletenessStatus;
  timestamp: string;
  nextUpdateAt: string;
}

interface ProtocolContribution {
  protocol: string;
  tvlShare: number;
  executionImpact: number;
  isDeepest: boolean;
}

interface DataCompletenessStatus {
  poolDepthAvailable: boolean;
  routeDataAvailable: boolean;
  missingProtocols: string[];
  isStale: boolean;
  staleSince?: string;
}

interface FragmentationAPIResponse {
  success: boolean;
  data: FragmentationMetrics;
  meta: {
    cacheStatus: 'HIT' | 'MISS' | 'STALE';
    computeTimeMs: number;
    nextUpdateAt: string;
  };
  warnings?: string[];
}

interface FragmentationErrorResponse {
  success: false;
  error: {
    code: string;
    message: string;
    details?: {
      missingProtocols?: string[];
      lastSuccessfulUpdate?: string;
    };
  };
}

/**
 * Custom error types for fragmentation service
 */
class DataUnavailableError extends Error {
  constructor(message: string, public lastSuccessfulUpdate?: string) {
    super(message);
    this.name = 'DataUnavailableError';
  }
}

class PartialDataError extends Error {
  constructor(message: string, public missingProtocols: string[]) {
    super(message);
    this.name = 'PartialDataError';
  }
}

class CalculationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'CalculationError';
  }
}

class InvalidRequestError extends Error {
  constructor(message: string, public details?: Record<string, string>) {
    super(message);
    this.name = 'InvalidRequestError';
  }
}

/**
 * Mock FragmentationService for now
 * In production, this will be imported from backend/keepers
 */
class MockFragmentationService {
  private cachedMetrics: FragmentationMetrics | null = null;
  private lastCalculation: number = 0;
  private lastSuccessfulUpdate: string | null = null;
  private readonly CACHE_TTL_MS = 300000; // 5 minutes
  private readonly STALE_CACHE_TTL_MS = 1800000; // 30 minutes

  // Test mode flags (for simulating error scenarios)
  private testMode: {
    simulateNoData?: boolean;
    simulatePartialData?: boolean;
    simulateCalculationError?: boolean;
    simulateStaleData?: boolean;
  } = {};

  setTestMode(mode: typeof this.testMode) {
    this.testMode = mode;
  }

  async getFragmentationMetrics(): Promise<FragmentationMetrics> {
    const now = Date.now();

    // Simulate complete data absence
    if (this.testMode.simulateNoData) {
      throw new DataUnavailableError(
        'No pool depth data available from any protocol',
        this.lastSuccessfulUpdate || undefined
      );
    }

    // Simulate calculation error
    if (this.testMode.simulateCalculationError) {
      throw new CalculationError('Invalid calculation result: HHI produced NaN');
    }

    // Check if cache is fresh
    if (this.cachedMetrics && (now - this.lastCalculation) < this.CACHE_TTL_MS) {
      // Simulate stale data scenario
      if (this.testMode.simulateStaleData) {
        return {
          ...this.cachedMetrics,
          dataCompleteness: {
            ...this.cachedMetrics.dataCompleteness,
            isStale: true,
            staleSince: new Date(now - 360000).toISOString(), // 6 minutes ago
          },
        };
      }
      return this.cachedMetrics;
    }

    // Simulate partial data scenario
    if (this.testMode.simulatePartialData) {
      throw new PartialDataError(
        'Pool depth data unavailable for some protocols',
        ['Aquarius']
      );
    }

    // Calculate fresh metrics (mock implementation)
    const timestamp = new Date().toISOString();
    const nextUpdateAt = new Date(now + this.CACHE_TTL_MS).toISOString();

    this.cachedMetrics = {
      fragmentationScore: 45.2,
      hhi: 5480,
      effectiveProtocolCount: 1.82,
      multiProtocolRoutingPct: 35.7,
      executionQualityScore: 72.3,
      materialImpact: false,
      category: 'Medium',
      categoryDescription: 'Liquidity is moderately distributed across protocols. Consider multi-protocol routing for larger trades.',
      protocolBreakdown: [
        {
          protocol: 'Blend',
          tvlShare: 62.5,
          executionImpact: 15.2,
          isDeepest: true,
        },
        {
          protocol: 'Soroswap',
          tvlShare: 24.3,
          executionImpact: 8.7,
          isDeepest: false,
        },
        {
          protocol: 'DeFindex',
          tvlShare: 13.2,
          executionImpact: 4.1,
          isDeepest: false,
        },
      ],
      dataCompleteness: {
        poolDepthAvailable: true,
        routeDataAvailable: true,
        missingProtocols: [],
        isStale: false,
      },
      timestamp,
      nextUpdateAt,
    };

    this.lastCalculation = now;
    this.lastSuccessfulUpdate = timestamp;
    return this.cachedMetrics;
  }

  /**
   * Get metrics with partial data (used when some protocols are unavailable)
   */
  async getPartialMetrics(missingProtocols: string[]): Promise<FragmentationMetrics> {
    const now = Date.now();
    const timestamp = new Date().toISOString();
    const nextUpdateAt = new Date(now + this.CACHE_TTL_MS).toISOString();

    // Calculate metrics with available protocols only
    const availableProtocols = [
      { protocol: 'Blend', tvlShare: 72.5, executionImpact: 18.2, isDeepest: true },
      { protocol: 'Soroswap', tvlShare: 27.5, executionImpact: 9.5, isDeepest: false },
    ];

    return {
      fragmentationScore: 39.8,
      hhi: 6020,
      effectiveProtocolCount: 1.66,
      multiProtocolRoutingPct: 28.3,
      executionQualityScore: 68.5,
      materialImpact: true,
      category: 'Medium',
      categoryDescription: 'Liquidity is moderately distributed across protocols. Consider multi-protocol routing for larger trades.',
      protocolBreakdown: availableProtocols,
      dataCompleteness: {
        poolDepthAvailable: true,
        routeDataAvailable: true,
        missingProtocols,
        isStale: false,
      },
      timestamp,
      nextUpdateAt,
    };
  }

  /**
   * Get stale cached metrics (used when data sources are unavailable)
   */
  getStaleMetrics(): FragmentationMetrics | null {
    const now = Date.now();

    // Check if we have stale cache available (within 30 minutes)
    if (this.cachedMetrics && (now - this.lastCalculation) < this.STALE_CACHE_TTL_MS) {
      return {
        ...this.cachedMetrics,
        dataCompleteness: {
          ...this.cachedMetrics.dataCompleteness,
          isStale: true,
          staleSince: new Date(this.lastCalculation + this.CACHE_TTL_MS).toISOString(),
        },
      };
    }

    return null;
  }

  isCacheHit(): boolean {
    const now = Date.now();
    return this.cachedMetrics !== null && (now - this.lastCalculation) < this.CACHE_TTL_MS;
  }
}

