/**
 * Issue #362: Adaptive Strategy Cooldown Optimizer
 *
 * Dynamically adjusts strategy cooldown windows based on volatility,
 * liquidity, recent execution outcomes, and market stress conditions.
 * Ensures critical safety pauses are never disabled.
 */

export interface StrategyMetrics {
  strategyId: string;
  strategyName: string;
  /** Recent rebalance frequency (rebalances per day). */
  rebalanceFrequency: number;
  /** Current volatility estimate (0-100 scale). */
  volatility: number;
  /** Liquidity score (0-100 scale, higher = better). */
  liquidityScore: number;
  /** Recent execution success rate (0-1). */
  executionSuccessRate: number;
  /** Last rebalance timestamp. */
  lastRebalanceAt: Date;
  /** Number of consecutive failed executions. */
  consecutiveFailures: number;
  /** Average slippage from last 10 executions (0-100 basis points). */
  averageSlippage: number;
}

export interface CooldownExpansionFactors {
  /** Factor due to high volatility (multiplier). */
  volatilityFactor: number;
  /** Factor due to poor liquidity (multiplier). */
  liquidityFactor: number;
  /** Factor due to recent failures (multiplier). */
  failuresFactor: number;
  /** Factor due to market stress (multiplier). */
  marketStressFactor: number;
}

export interface CooldownRecommendation {
  strategyId: string;
  strategyName: string;
  /** Recommended cooldown in milliseconds. */
  recommendedCooldownMs: number;
  /** Current baseline cooldown. */
  baselineCooldownMs: number;
  /** Reason for expansion/contraction. */
  reason: string;
  /** Breakdown of all expansion factors. */
  factors: CooldownExpansionFactors;
  /** Total multiplier applied. */
  totalMultiplier: number;
  /** Confidence in recommendation (0-1). */
  confidence: number;
  /** Time this recommendation was generated. */
  generatedAt: Date;
}

export interface CooldownOptimizerConfig {
  /** Baseline cooldown for all strategies (ms). */
  baselineCooldownMs: number;
  /** Minimum cooldown floor (never go below). */
  minCooldownMs: number;
  /** Maximum cooldown ceiling (never go above). */
  maxCooldownMs: number;
  /** Volatility threshold for expansion (0-100). */
  volatilityThreshold: number;
  /** Liquidity threshold for expansion (0-100). */
  liquidityThreshold: number;
  /** Max consecutive failures before expanding cooldown. */
  maxConsecutiveFailures: number;
  /** Market stress multiplier. */
  marketStressMultiplier: number;
}

export const DEFAULT_COOLDOWN_CONFIG: CooldownOptimizerConfig = {
  baselineCooldownMs: 24 * 60 * 60 * 1000, // 24 hours
  minCooldownMs: 60 * 60 * 1000, // 1 hour (safety floor)
  maxCooldownMs: 14 * 24 * 60 * 60 * 1000, // 14 days (ceiling)
  volatilityThreshold: 60,
  liquidityThreshold: 40,
  maxConsecutiveFailures: 3,
  marketStressMultiplier: 1.5,
};

/**
 * Adaptive Cooldown Optimizer Service
 *
 * Computes dynamic cooldown recommendations per strategy based on:
 * - Market volatility
 * - Liquidity conditions
 * - Recent execution outcomes
 * - Market stress levels
 * - Failure patterns
 *
 * All recommendations respect configured floor/ceiling constraints.
 */
export class AdaptiveCooldownOptimizer {
  constructor(private config: CooldownOptimizerConfig = DEFAULT_COOLDOWN_CONFIG) {}

  /**
   * Computes expansion factors based on strategy metrics.
   */
  private computeExpansionFactors(
    metrics: StrategyMetrics,
    isUnderMarketStress: boolean,
  ): CooldownExpansionFactors {
    // Volatility factor: higher volatility = longer cooldown
    const volatilityFactor = Math.max(
      1.0,
      1 +
        Math.max(0, metrics.volatility - this.config.volatilityThreshold) /
          100 *
          0.5, // Up to 50% expansion
    );

    // Liquidity factor: lower liquidity = longer cooldown
    const liquidityFactor = Math.max(
      1.0,
      1 +
        Math.max(0, this.config.liquidityThreshold - metrics.liquidityScore) /
          100 *
          0.5, // Up to 50% expansion
    );

    // Failures factor: consecutive failures = longer cooldown
    const failuresFactor = Math.max(
      1.0,
      1 +
        Math.min(
          metrics.consecutiveFailures,
          this.config.maxConsecutiveFailures,
        ) /
          this.config.maxConsecutiveFailures *
          0.75, // Up to 75% expansion
    );

    // Execution success rate: lower success = expansion
    const successFactor = Math.max(
      1.0,
      1 + (1 - metrics.executionSuccessRate) * 0.4, // Up to 40% expansion
    );

    // Slippage factor: higher slippage = expansion
    const slippageFactor = Math.max(1.0, 1 + metrics.averageSlippage / 100 * 0.3); // Up to 30% expansion

    // Market stress: global override for stress conditions
    const marketStressFactor = isUnderMarketStress
      ? this.config.marketStressMultiplier
      : 1.0;

    return {
      volatilityFactor,
      liquidityFactor,
      failuresFactor,
      marketStressFactor,
    };
  }

  /**
   * Generates a cooldown recommendation for a strategy.
   *
   * @param metrics Strategy performance and market metrics
   * @param isUnderMarketStress Whether system is under stress
   * @returns CooldownRecommendation with detailed reasoning
   */
  recommendCooldown(
    metrics: StrategyMetrics,
    isUnderMarketStress: boolean = false,
  ): CooldownRecommendation {
    const factors = this.computeExpansionFactors(metrics, isUnderMarketStress);

    // Aggregate all multipliers
    const totalMultiplier =
      factors.volatilityFactor *
      factors.liquidityFactor *
      factors.failuresFactor *
      factors.marketStressFactor;

    // Apply multiplier to baseline
    let recommendedMs = this.config.baselineCooldownMs * totalMultiplier;

    // Enforce floor and ceiling
    recommendedMs = Math.max(
      this.config.minCooldownMs,
      Math.min(this.config.maxCooldownMs, recommendedMs),
    );

    // Build reason string
    const reasons: string[] = [];
    if (factors.volatilityFactor > 1.0) {
      reasons.push(`high volatility (${metrics.volatility.toFixed(1)})`);
    }
    if (factors.liquidityFactor > 1.0) {
      reasons.push(`low liquidity (${metrics.liquidityScore.toFixed(1)})`);
    }
    if (factors.failuresFactor > 1.0) {
      reasons.push(`${metrics.consecutiveFailures} consecutive failures`);
    }
    if (isUnderMarketStress) {
      reasons.push("market stress detected");
    }

    const reason =
      reasons.length > 0
        ? `Cooldown expanded due to: ${reasons.join(", ")}`
        : "Normal market conditions";

    // Confidence: lower when multiple factors are pushing expansion
    const expansionCount = [
      factors.volatilityFactor > 1.0,
      factors.liquidityFactor > 1.0,
      factors.failuresFactor > 1.0,
      isUnderMarketStress,
    ].filter(Boolean).length;

    const confidence = Math.max(0.5, 1 - expansionCount * 0.15);

    return {
      strategyId: metrics.strategyId,
      strategyName: metrics.strategyName,
      recommendedCooldownMs: Math.round(recommendedMs),
      baselineCooldownMs: this.config.baselineCooldownMs,
      reason,
      factors,
      totalMultiplier,
      confidence,
      generatedAt: new Date(),
    };
  }

  /**
   * Batch recommend cooldowns for multiple strategies.
   */
  recommendCooldownsBatch(
    metrics: StrategyMetrics[],
    isUnderMarketStress: boolean = false,
  ): CooldownRecommendation[] {
    return metrics.map((m) => this.recommendCooldown(m, isUnderMarketStress));
  }

  /**
   * Format cooldown duration for display.
   */
  static formatDuration(ms: number): string {
    const hours = Math.floor(ms / (60 * 60 * 1000));
    const days = Math.floor(hours / 24);

    if (days > 0) {
      return `${days}d ${hours % 24}h`;
    }
    return `${hours}h`;
  }

  /**
   * Check if a strategy needs cooldown expansion.
   */
  shouldExpandCooldown(
    metrics: StrategyMetrics,
    isUnderMarketStress: boolean = false,
  ): boolean {
    const recommendation = this.recommendCooldown(metrics, isUnderMarketStress);
    return (
      recommendation.recommendedCooldownMs >
      this.config.baselineCooldownMs * 1.1
    );
  }

  /**
   * Check if a strategy can contract cooldown.
   */
  shouldContractCooldown(
    metrics: StrategyMetrics,
    isUnderMarketStress: boolean = false,
  ): boolean {
    if (isUnderMarketStress) return false;
    return (
      metrics.volatility <= this.config.volatilityThreshold &&
      metrics.liquidityScore >= this.config.liquidityThreshold &&
      metrics.consecutiveFailures === 0 &&
      metrics.executionSuccessRate >= 0.95
    );
  }
}

/**
 * Issue #478: Improve Backtest Date Range Validation Messages
 *
 * Enhanced backtest service with comprehensive validation for date ranges,
 * future dates, and overly long windows.
 */

import type { BacktestRequest, BacktestResult, DailySnapshot } from "./types";
import {
  validateDateRange,
  validateNumericRange,
  validateRequired,
  ValidationException,
  collectValidationErrors,
} from "../utils/validationHelper";

// Constants
const MAX_BACKTEST_WINDOW_DAYS = 730; // 2 years
const MIN_BACKTEST_WINDOW_DAYS = 1;

export interface BacktestValidationResult {
  isValid: boolean;
  errors: Array<{
    code: string;
    message: string;
    field?: string;
  }>;
}

/**
 * Validates backtest request parameters with detailed error reporting.
 * Returns specific error codes for each validation failure.
 *
 * @returns BacktestValidationResult with specific error codes and messages
 */
export function validateBacktestRequest(
  request: BacktestRequest,
): BacktestValidationResult {
  const errors: Array<{ code: string; message: string; field?: string }> = [];

  try {
    // Required fields validation
    const requiredErrors = validateRequired(request as unknown as Record<string, unknown>, [
      "startDate",
      "endDate",
      "depositAmount",
    ]);

    errors.push(
      ...requiredErrors.map((e) => ({
        code: e.code,
        message: e.message,
        field: e.details?.field as string,
      })),
    );

    // Early exit if required fields are missing
    if (errors.length > 0) {
      return { isValid: false, errors };
    }

    // Parse dates
    let startDate: Date;
    let endDate: Date;

    try {
      startDate = new Date(request.startDate);
      endDate = new Date(request.endDate);

      if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
        throw new Error("Invalid date format");
      }
    } catch {
      errors.push({
        code: "INVALID_DATE_FORMAT",
        message: "Start and end dates must be valid ISO-8601 date strings",
        field: "dates",
      });
      return { isValid: false, errors };
    }

    // Date range validation
    const dateErrors = validateDateRange(startDate, endDate, {
      maxWindowDays: MAX_BACKTEST_WINDOW_DAYS,
      minWindowDays: MIN_BACKTEST_WINDOW_DAYS,
      allowFutureDates: false,
    });

    errors.push(
      ...dateErrors.map((e) => ({
        code: e.code,
        message: e.message,
      })),
    );

    // Deposit amount validation
    const depositAmount = BigInt(request.depositAmount);
    if (depositAmount <= 0n) {
      errors.push({
        code: "INVALID_DEPOSIT_AMOUNT",
        message: "Deposit amount must be greater than zero",
        field: "depositAmount",
      });
    }

    // vault ID validation
    if (!request.vaultContractId || request.vaultContractId.trim().length === 0) {
      errors.push({
        code: "INVALID_VAULT_ID",
        message: "Vault contract ID must be a non-empty string",
        field: "vaultContractId",
      });
    }
  } catch (err) {
    // Catch unexpected errors
    if (err instanceof ValidationException) {
      errors.push(
        ...err.errors.map((e) => ({
          code: e.code,
          message: e.message,
        })),
      );
    } else {
      errors.push({
        code: "VALIDATION_ERROR",
        message: err instanceof Error ? err.message : "Unknown validation error",
      });
    }
  }

  return {
    isValid: errors.length === 0,
    errors,
  };
}

/**
 * Fetch backtest data from backend with validation
 *
 * @throws Error with specific validation message if request is invalid
 */
export async function fetchBacktestData(request: BacktestRequest): Promise<BacktestResult> {
  // Validate request
  const validation = validateBacktestRequest(request);
  if (!validation.isValid) {
    const errorMessage = validation.errors.map((e) => `${e.code}: ${e.message}`).join("; ");
    throw new Error(`Backtest validation failed: ${errorMessage}`);
  }

  const params = new URLSearchParams({
    vaultContractId: request.vaultContractId,
    startDate: request.startDate,
    endDate: request.endDate,
    depositAmount: request.depositAmount.toString(),
  });

  const response = await fetch(`/api/backtest?${params}`, {
    method: "GET",
    headers: { "Content-Type": "application/json" },
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Backtest failed (${response.status}): ${errorText}`);
  }

  return (await response.json()) as BacktestResult;
}

/**
 * Calculate compound interest from daily APY snapshots.
 * Used for client-side simulation with high precision.
 */
export function calculateCompoundInterest(
  initialAmount: bigint,
  snapshots: DailySnapshot[],
): DailySnapshot[] {
  if (snapshots.length === 0) return [];

  const results: DailySnapshot[] = [];
  let currentValue = initialAmount;

  for (let i = 0; i < snapshots.length; i++) {
    const snapshot = snapshots[i];
    const apy = snapshot.apy ?? 0;
    const dailyRate = apy / 365 / 100;
    currentValue = (currentValue * BigInt(Math.round((1 + dailyRate) * 1e9))) / BigInt(1e9);

    results.push({
      date: snapshot.date,
      balance: currentValue,
      yieldEarned: currentValue - initialAmount,
      apy,
      equityValue: currentValue,
    });
  }

  return results;
}

/**
 * Calculate total return percentage from initial and final amounts.
 */
export function calculateTotalReturn(initial: bigint, final: bigint): number {
  if (initial === 0n) return 0;
  return (Number(final - initial) / Number(initial)) * 100;
}

/**
 * Issue #285: On-Chain Event Compression and Archive Service
 *
 * Provides archival pipeline for historical event records with:
 * - Compression and partitioning of old events
 * - Preserved query access for audit/analytics
 * - Data integrity during rollover
 */

export interface EventArchiveRecord {
  id: string;
  contractId: string;
  topic: string;
  data: string;
  txHash: string;
  ledger: number;
  createdAt: Date;
}

export interface ArchiveMetadata {
  archiveId: string;
  startDate: Date;
  endDate: Date;
  eventCount: number;
  compressedSize: number; // bytes
  originalSize: number; // bytes
  compressionRatio: number;
  status: "pending" | "processing" | "completed" | "failed";
  createdAt: Date;
  completedAt?: Date;
  checksumHash: string; // SHA-256 for integrity
  error?: string;
}

export interface ArchiveQueryResult {
  records: EventArchiveRecord[];
  totalCount: number;
  archiveIds: string[];
  queryTimeMs: number;
}

export interface ArchiveServiceConfig {
  /** Days before an event becomes eligible for archival. */
  archivalThresholdDays: number;
  /** Batch size for archival jobs. */
  batchSize: number;
  /** Maximum archive file size in bytes. */
  maxArchiveSizeBytes: number;
  /** Whether to compress archives. */
  compressionEnabled: boolean;
  /** Partition strategy: "daily", "weekly", "monthly". */
  partitionStrategy: "daily" | "weekly" | "monthly";
  /** Retention policy: how long to keep archives (days). */
  retentionDays: number;
}

export const DEFAULT_ARCHIVE_CONFIG: ArchiveServiceConfig = {
  archivalThresholdDays: 90,
  batchSize: 10000,
  maxArchiveSizeBytes: 100 * 1024 * 1024, // 100 MB
  compressionEnabled: true,
  partitionStrategy: "monthly",
  retentionDays: 7 * 365, // 7 years
};

import crypto from "crypto";
import zlib from "zlib";
import { promisify } from "util";

const gzip = promisify(zlib.gzip);
const gunzip = promisify(zlib.gunzip);

/**
 * Event Compression and Archive Service
 *
 * Manages archival, compression, and queryable storage of historical events.
 * Ensures data integrity and preserves audit trail.
 */
export class EventArchiveService {
  private config: ArchiveServiceConfig;
  private archives: Map<string, ArchiveMetadata> = new Map();

  constructor(config: Partial<ArchiveServiceConfig> = {}) {
    this.config = { ...DEFAULT_ARCHIVE_CONFIG, ...config };
  }

  /**
   * Calculate SHA-256 checksum for data integrity verification.
   */
  private calculateChecksum(data: string | Buffer): string {
    return crypto.createHash("sha256").update(data).digest("hex");
  }

  /**
   * Compress event data using gzip for efficient storage.
   */
  async compressEventData(events: EventArchiveRecord[]): Promise<Buffer> {
    const jsonData = JSON.stringify(events);
    if (!this.config.compressionEnabled) {
      return Buffer.from(jsonData);
    }
    return gzip(jsonData);
  }

  /**
   * Decompress archived events for retrieval.
   */
  async decompressEventData(compressedData: Buffer): Promise<EventArchiveRecord[]> {
    const reviver = (key: string, value: any) => {
      if (key === 'createdAt' && typeof value === 'string') {
        return new Date(value);
      }
      return value;
    };
    try {
      const decompressed = await gunzip(compressedData);
      return JSON.parse(decompressed.toString(), reviver);
    } catch {
      return JSON.parse(compressedData.toString(), reviver);
    }
  }

  /**
   * Generate partition key based on date and strategy.
   */
  private getPartitionKey(date: Date): string {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const day = String(date.getDate()).padStart(2, "0");
    const week = Math.floor(date.getDate() / 7) + 1;

    switch (this.config.partitionStrategy) {
      case "daily":
        return `${year}-${month}-${day}`;
      case "weekly":
        return `${year}-W${String(week).padStart(2, "0")}`;
      case "monthly":
      default:
        return `${year}-${month}`;
    }
  }

  /**
   * Archive a batch of events.
   * Returns metadata about the archive created.
   */
  async archiveEvents(
    events: EventArchiveRecord[],
    checkIntegrity: boolean = true,
  ): Promise<ArchiveMetadata> {
    if (events.length === 0) {
      throw new Error("Cannot archive empty event batch");
    }

    const archiveId = `archive_${Date.now()}_${crypto.randomBytes(4).toString("hex")}`;
    const startDate = new Date(Math.min(...events.map((e) => e.createdAt.getTime())));
    const endDate = new Date(Math.max(...events.map((e) => e.createdAt.getTime())));

    const metadata: ArchiveMetadata = {
      archiveId,
      startDate,
      endDate,
      eventCount: events.length,
      originalSize: JSON.stringify(events).length,
      compressedSize: 0,
      compressionRatio: 0,
      status: "pending",
      createdAt: new Date(),
      checksumHash: "",
    };

    try {
      metadata.status = "processing";

      // Compress events
      const compressedData = await this.compressEventData(events);
      metadata.compressedSize = compressedData.length;
      metadata.compressionRatio = metadata.compressedSize / metadata.originalSize;

      // Calculate checksum
      metadata.checksumHash = this.calculateChecksum(compressedData);

      // Validate integrity if requested
      if (checkIntegrity) {
        const decompressed = await this.decompressEventData(compressedData);
        if (decompressed.length !== events.length) {
          throw new Error("Integrity check failed: event count mismatch after decompression");
        }
      }

      metadata.status = "completed";
      metadata.completedAt = new Date();
    } catch (error) {
      metadata.status = "failed";
      metadata.error = error instanceof Error ? error.message : "Unknown error";
    }

    this.archives.set(archiveId, metadata);
    return metadata;
  }

  /**
   * Query events across multiple archives.
   * Returns results from specified date range and topics.
   */
  async queryArchives(
    startDate: Date,
    endDate: Date,
    filters?: {
      contractId?: string;
      topic?: string;
    },
  ): Promise<ArchiveQueryResult> {
    const startTime = Date.now();
    const results: EventArchiveRecord[] = [];
    const archiveIds: string[] = [];

    for (const [archiveId, metadata] of this.archives) {
      // Skip if archive is outside date range
      if (
        metadata.endDate < startDate ||
        metadata.startDate > endDate ||
        metadata.status !== "completed"
      ) {
        continue;
      }

      archiveIds.push(archiveId);

      // In production, would fetch from storage
      // For now, tracking as retrieved
    }

    const queryTimeMs = Date.now() - startTime;

    return {
      records: results,
      totalCount: results.length,
      archiveIds,
      queryTimeMs,
    };
  }

  /**
   * Get archive metadata by ID.
   */
  getArchiveMetadata(archiveId: string): ArchiveMetadata | undefined {
    return this.archives.get(archiveId);
  }

  /**
   * List all archives with optional filtering.
   */
  listArchives(
    filters?: {
      status?: "pending" | "processing" | "completed" | "failed";
      startDate?: Date;
      endDate?: Date;
    },
  ): ArchiveMetadata[] {
    let archives = Array.from(this.archives.values());

    if (filters?.status) {
      archives = archives.filter((a) => a.status === filters.status);
    }

    if (filters?.startDate) {
      archives = archives.filter((a) => a.endDate >= filters.startDate!);
    }

    if (filters?.endDate) {
      archives = archives.filter((a) => a.startDate <= filters.endDate!);
    }

    return archives.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
  }

  /**
   * Verify archive integrity by checksum.
   */
  async verifyArchiveIntegrity(archiveId: string, data: Buffer): Promise<boolean> {
    const metadata = this.archives.get(archiveId);
    if (!metadata) {
      throw new Error(`Archive not found: ${archiveId}`);
    }

    const calculatedHash = this.calculateChecksum(data);
    return calculatedHash === metadata.checksumHash;
  }

  /**
   * Delete archive (after retention period).
   */
  deleteArchive(archiveId: string): boolean {
    return this.archives.delete(archiveId);
  }

  /**
   * Get archival statistics.
   */
  getArchiveStats(): {
    totalArchives: number;
    completedArchives: number;
    totalEventsArchived: number;
    totalStorageBytes: number;
    averageCompressionRatio: number;
  } {
    const archives = Array.from(this.archives.values());
    const completed = archives.filter((a) => a.status === "completed");

    const totalEventsArchived = completed.reduce((sum, a) => sum + a.eventCount, 0);
    const totalStorageBytes = completed.reduce((sum, a) => sum + a.compressedSize, 0);
    const averageCompressionRatio =
      completed.length > 0
        ? completed.reduce((sum, a) => sum + a.compressionRatio, 0) / completed.length
        : 0;

    return {
      totalArchives: archives.length,
      completedArchives: completed.length,
      totalEventsArchived,
      totalStorageBytes,
      averageCompressionRatio,
    };
  }
}

/**
 * Fallback Tree Integration Layer
 *
 * Integrates the hierarchical fallback tree with existing strategy services
 * to provide degraded recommendation paths when primary strategies fail.
 *
 * This layer bridges the fallback tree service with:
 * - Strategy Health Service for health checks
 * - Protocol Failover Service for blocklist checks
 * - Strategy Rotation Service for candidate prioritization
 */

import {
  fallbackTreeRegistry,
  type FallbackNode,
  type TraversalContext,
  type TraversalResult,
  createFallbackTreeFromList,
  formatTraversalResult,
  extractFailedNodes,
} from './fallbackTreeService';
import {
  strategyHealthEngine,
  type StrategyHealthScore,
  isStrategySafeForExecution,
} from './strategyHealthService';
import {
  failoverRegistry,
  type ProtocolHealthInput,
} from './protocolFailoverService';
import {
  rotationRegistry,
  type RotationCandidate,
} from './strategyRotationService';

// ── Types ───────────────────────────────────────────────────────────────

export interface StrategyRecommendationContext {
  /** Current strategy ID (if any) */
  currentStrategyId?: string;
  /** Available strategies with their metadata */
  availableStrategies: Array<{
    id: string;
    name: string;
    priority?: number;
    protocolId?: string;
  }>;
  /** Minimum health score threshold */
  minHealthScore?: number;
  /** Whether to allow degraded strategies */
  allowDegraded?: boolean;
  /** Maximum fallback depth */
  maxDepth?: number;
}

export interface RecommendationResult {
  /** Recommended strategy */
  recommendedStrategy: {
    id: string;
    name: string;
  } | null;
  /** Full fallback tree traversal result */
  traversalResult: TraversalResult;
  /** Whether recommendation was made from fallback */
  isFallback: boolean;
  /** Fallback depth (0 = primary, >0 = fallback level) */
  fallbackDepth: number;
  /** Human-readable explanation */
  explanation: string;
  /** Timestamp of recommendation */
  recommendedAt: string;
}

// ── Integration Functions ───────────────────────────────────────────────

/**
 * Create a fallback tree from available strategies with optional priority ordering
 */
export function createStrategyFallbackTree(
  strategies: Array<{ id: string; name: string; priority?: number }>,
  sortBy: 'priority' | 'health' | 'rotation' = 'priority',
): FallbackNode {
  if (sortBy === 'priority') {
    return createFallbackTreeFromList(strategies);
  }

  // For other sorting modes, we'd need to fetch additional data
  // For now, default to priority-based sorting
  return createFallbackTreeFromList(strategies);
}

/**
 * Get strategy health check function integrated with StrategyHealthService
 */
function createStrategyHealthChecker(minHealthScore: number = 50) {
  return async (strategyId: string) => {
    try {
      const healthScore = await strategyHealthEngine.calculateHealthScore(
        strategyId,
        `Strategy ${strategyId}`,
      );

      return {
        status: healthScore.status as 'healthy' | 'degraded' | 'critical' | 'blocked' | 'unknown',
        score: healthScore.overallScore,
        checkedAt: healthScore.lastUpdated,
        reasons: healthScore.recommendations,
      };
    } catch (error) {
      // If health check fails, treat as unknown status
      return {
        status: 'unknown' as const,
        score: 0,
        checkedAt: new Date().toISOString(),
        reasons: ['Health check failed'],
      };
    }
  };
}

/**
 * Get strategy blocklist check function integrated with ProtocolFailoverService
 */
function createStrategyBlocklistChecker() {
  return async (strategyId: string) => {
    const excludedProtocols = failoverRegistry.excludedProtocols();
    const isExcluded = excludedProtocols.includes(strategyId);

    return {
      isBlocked: isExcluded,
      reason: isExcluded ? 'Excluded by protocol failover service' : undefined,
      checkedAt: new Date().toISOString(),
    };
  };
}

/**
 * Get recommendation using fallback tree traversal in degraded paths
 *
 * This is the main integration point for using fallback trees in recommendation
 * paths. It:
 * 1. Creates a fallback tree from available strategies
 * 2. Traverses the tree using health and blocklist checks
 * 3. Returns the first viable strategy with full audit trail
 */
export async function getStrategyRecommendation(
  context: StrategyRecommendationContext,
): Promise<RecommendationResult> {
  const now = Date.now();
  const minHealthScore = context.minHealthScore ?? 50;
  const allowDegraded = context.allowDegraded ?? true;
  const maxDepth = context.maxDepth ?? 20;

  // Create fallback tree from available strategies
  const tree = createStrategyFallbackTree(context.availableStrategies, 'priority');

  // Register tree temporarily for this recommendation
  const treeKey = `recommendation-${now}`;
  fallbackTreeRegistry.registerTree(treeKey, tree);

  try {
    // Create traversal context with integrated health and blocklist checks
    const traversalContext: TraversalContext = {
      checkHealth: createStrategyHealthChecker(minHealthScore),
      checkBlocklist: createStrategyBlocklistChecker(),
      minHealthScore,
      allowDegraded,
      maxDepth,
      now,
    };

    // Traverse the fallback tree
    const traversalResult = await fallbackTreeRegistry.traverse(
      treeKey,
      traversalContext,
    );

    // Determine if this is a fallback recommendation
    const isFallback = traversalResult.path.length > 1;
    const fallbackDepth = isFallback ? traversalResult.maxDepthReached : 0;

    // Build explanation
    let explanation: string;
    if (traversalResult.terminalFailure) {
      explanation = `No viable strategy found. ${traversalResult.terminalFailureReason}. Evaluated ${traversalResult.nodesEvaluated} strategies.`;
    } else if (isFallback) {
      const failedNodes = extractFailedNodes(traversalResult);
      const failedReasons = failedNodes
        .slice(0, 3)
        .map(n => `${n.nodeName} (${n.reason})`)
        .join(', ');
      explanation = `Recommended ${traversalResult.selectedNode?.name} as fallback. Primary strategies unavailable: ${failedReasons}${failedNodes.length > 3 ? '...' : ''}.`;
    } else {
      explanation = `Recommended primary strategy ${traversalResult.selectedNode?.name}. All health checks passed.`;
    }

    return {
      recommendedStrategy: traversalResult.selectedNode
        ? {
            id: traversalResult.selectedNode.id,
            name: traversalResult.selectedNode.name,
          }
        : null,
      traversalResult,
      isFallback,
      fallbackDepth,
      explanation,
      recommendedAt: new Date(now).toISOString(),
    };
  } finally {
    // Clean up temporary tree
    fallbackTreeRegistry.removeTree(treeKey);
  }
}

/**
 * Get recommendation with rotation candidates integration
 *
 * This variant integrates with the Strategy Rotation Service to prioritize
 * candidates based on rotation decisions before applying fallback logic.
 */
export async function getRotatedStrategyRecommendation(
  context: StrategyRecommendationContext,
): Promise<RecommendationResult> {
  // Convert available strategies to rotation candidates
  const rotationCandidates: RotationCandidate[] = context.availableStrategies.map(
    (strategy) => ({
      id: strategy.id,
      name: strategy.name,
      score: strategy.priority ?? 0, // Use priority as initial score
      fetchedAt: new Date().toISOString(),
    }),
  );

  // Get rotation decision
  const rotationDecision = rotationRegistry.evaluate(rotationCandidates);

  // If rotation selected a strategy, prioritize it in the fallback tree
  let prioritizedStrategies = [...context.availableStrategies];
  if (rotationDecision.action === 'rotate' && rotationDecision.toId) {
    const rotatedStrategy = context.availableStrategies.find(
      (s) => s.id === rotationDecision.toId,
    );
    if (rotatedStrategy) {
      // Move rotated strategy to front with highest priority
      prioritizedStrategies = [
        { ...rotatedStrategy, priority: 999 },
        ...context.availableStrategies.filter((s) => s.id !== rotationDecision.toId),
      ];
    }
  }

  // Get recommendation with prioritized strategies
  return getStrategyRecommendation({
    ...context,
    availableStrategies: prioritizedStrategies,
  });
}

/**
 * Get degraded path recommendation for a specific protocol
 *
 * This function provides protocol-specific fallback recommendations,
 * useful when a particular protocol is experiencing issues.
 */
export async function getProtocolFallbackRecommendation(
  protocolId: string,
  context: StrategyRecommendationContext,
): Promise<RecommendationResult> {
  // Filter strategies by protocol
  const protocolStrategies = context.availableStrategies.filter(
    (s) => s.protocolId === protocolId,
  );

  if (protocolStrategies.length === 0) {
    // No strategies for this protocol, fall back to all strategies
    return getStrategyRecommendation(context);
  }

  // Check if protocol is excluded by failover service
  const excludedProtocols = failoverRegistry.excludedProtocols();
  const isProtocolExcluded = excludedProtocols.includes(protocolId);

  if (isProtocolExcluded) {
    // Protocol is excluded, recommend from other protocols
    const otherProtocolStrategies = context.availableStrategies.filter(
      (s) => s.protocolId !== protocolId,
    );
    return getStrategyRecommendation({
      ...context,
      availableStrategies: otherProtocolStrategies,
    });
  }

  // Protocol is healthy, recommend from its strategies
  return getStrategyRecommendation({
    ...context,
    availableStrategies: protocolStrategies,
  });
}

/**
 * Get recommendation with health-based prioritization
 *
 * This variant fetches health scores for all strategies first,
 * then prioritizes them by health score before fallback traversal.
 */
export async function getHealthPrioritizedRecommendation(
  context: StrategyRecommendationContext,
): Promise<RecommendationResult> {
  // Fetch health scores for all strategies
  const healthScores = await Promise.all(
    context.availableStrategies.map(async (strategy) => {
      try {
        const health = await strategyHealthEngine.calculateHealthScore(
          strategy.id,
          strategy.name,
        );
        return {
          strategy,
          healthScore: health.overallScore,
          status: health.status,
        };
      } catch {
        return {
          strategy,
          healthScore: 0,
          status: 'critical' as const,
        };
      }
    }),
  );

  // Sort by health score (descending)
  const sortedStrategies = healthScores
    .sort((a, b) => b.healthScore - a.healthScore)
    .map((item) => ({
      ...item.strategy,
      priority: item.healthScore, // Use health score as priority
    }));

  // Get recommendation with health-prioritized strategies
  return getStrategyRecommendation({
    ...context,
    availableStrategies: sortedStrategies,
  });
}

// ── Monitoring and Analytics ─────────────────────────────────────────────

/**
 * Get fallback tree statistics for monitoring
 */
export function getFallbackTreeStatistics() {
  const history = fallbackTreeRegistry.getTraversalHistory(1000);

  const stats = {
    totalTraversals: history.length,
    successfulTraversals: history.filter((h) => !h.terminalFailure).length,
    failedTraversals: history.filter((h) => h.terminalFailure).length,
    averageNodesEvaluated:
      history.reduce((sum, h) => sum + h.nodesEvaluated, 0) / history.length || 0,
    averageDepthReached:
      history.reduce((sum, h) => sum + h.maxDepthReached, 0) / history.length || 0,
    mostCommonFailureReasons: getMostCommonFailureReasons(history),
  };

  return stats;
}

/**
 * Get most common failure reasons from traversal history
 */
function getMostCommonFailureReasons(history: TraversalResult[]): Array<{
  reason: string;
  count: number;
}> {
  const reasonCounts = new Map<string, number>();

  history.forEach((result) => {
    if (result.terminalFailure && result.terminalFailureReason) {
      const count = reasonCounts.get(result.terminalFailureReason) || 0;
      reasonCounts.set(result.terminalFailureReason, count + 1);
    }
  });

  return Array.from(reasonCounts.entries())
    .map(([reason, count]) => ({ reason, count }))
    .sort((a, b) => b.count - a.count)
    .slice(0, 5);
}

/**
 * Get recent recommendation history for a specific strategy
 */
export function getStrategyRecommendationHistory(
  strategyId: string,
  limit = 50,
): TraversalResult[] {
  const allHistory = fallbackTreeRegistry.getTraversalHistory(limit);
  return allHistory.filter((result) =>
    result.path.some((step) => step.nodeId === strategyId),
  );
}

import crypto from "crypto";
import { DEFAULT_ICON_CONFIG } from "../../utils/iconValidator";

export interface VaultMetadataInput {
  vaultName: string;
  description: string;
  iconSvg: string;
}

export interface VaultMetadataPayload {
  name: string;
  description: string;
  icon: string;
  createdAt: string;
}

export interface UploadVaultMetadataResult {
  cid: string;
  metadataUri: string;
  iconUri: string;
  metadata: VaultMetadataPayload;
  uploadMode: "pinata" | "local-fallback";
}

const PINATA_FILE_API = "https://api.pinata.cloud/pinning/pinFileToIPFS";
const PINATA_JSON_API = "https://api.pinata.cloud/pinning/pinJSONToIPFS";

function requireNonEmpty(value: string, field: string): string {
  const trimmed = value?.trim();
  if (!trimmed) {
    throw new Error(`${field} is required`);
  }
  return trimmed;
}

function extractSvgDimensionsFromString(svg: string): { width: number; height: number } | null {
  const viewBoxMatch = svg.match(/viewBox\s*=\s*["']([^"']+)["']/i);
  if (viewBoxMatch) {
    const values = viewBoxMatch[1].split(/\s+/).map(Number);
    if (values.length === 4 && !values.some(isNaN)) {
      return { width: values[2], height: values[3] };
    }
  }

  const widthMatch = svg.match(/width\s*=\s*["']?(\d+)/i);
  const heightMatch = svg.match(/height\s*=\s*["']?(\d+)/i);

  if (widthMatch && heightMatch) {
    return {
      width: parseInt(widthMatch[1], 10),
      height: parseInt(heightMatch[1], 10),
    };
  }

  return null;
}

/**
 * Iteratively applies a replacement until the string stabilises.
 * This prevents bypass via nested payloads such as `<scr<script>ipt>`.
 */
function replaceUntilStable(input: string, pattern: RegExp, replacement: string): string {
  let previous = input;
  // eslint-disable-next-line no-constant-condition
  while (true) {
    const next = previous.replace(pattern, replacement);
    if (next === previous) return next;
    previous = next;
  }
}

/**
 * Strip `<script ...>...</script ...>` blocks using indexOf scanning.
 * O(n) with zero backtracking risk.  Handles `</script >` (whitespace
 * before `>`) and self-closing `<script ... />` forms.
 */
function stripScriptTags(input: string): string {
  let result = input;
  // eslint-disable-next-line no-constant-condition
  while (true) {
    const openIdx = result.search(/<script[\s>\/]/i);
    if (openIdx === -1) break;

    // Look for the closing </script...> tag
    const closeTagStart = result.search(/<\/script[\s>]/i);
    if (closeTagStart !== -1 && closeTagStart > openIdx) {
      // Find the `>` that actually ends the closing tag
      const closeTagEnd = result.indexOf('>', closeTagStart);
      if (closeTagEnd !== -1) {
        result = result.slice(0, openIdx) + result.slice(closeTagEnd + 1);
        continue;
      }
    }

    // No proper closing tag found — remove from <script to end of its opening tag
    const openTagEnd = result.indexOf('>', openIdx);
    if (openTagEnd !== -1) {
      result = result.slice(0, openIdx) + result.slice(openTagEnd + 1);
    } else {
      // Malformed: no closing `>` at all — truncate from <script onward
      result = result.slice(0, openIdx);
    }
  }
  return result;
}

export function sanitizeSvg(svg: string): string {
  const normalized = requireNonEmpty(svg, "iconSvg");

  if (!normalized.includes("<svg")) {
    throw new Error("iconSvg must be a valid SVG string");
  }

  // 1. Strip <script> blocks via linear indexOf scanning (no regex).
  let sanitized = stripScriptTags(normalized);

  // 2. Strip inline event handlers (on*="…", on*='…', unquoted).
  //    Each regex uses a bounded character class — no nested quantifiers.
  sanitized = replaceUntilStable(sanitized, /(?<=\s|^|['"\/])on\w+\s*=\s*"[^"]*"/gi, "");
  sanitized = replaceUntilStable(sanitized, /(?<=\s|^|['"\/])on\w+\s*=\s*'[^']*'/gi, "");
  sanitized = replaceUntilStable(sanitized, /(?<=\s|^|['"\/])on\w+\s*=\s*[^\s>"']+/gi, "");

  // 3. Strip dangerous URI schemes (javascript:, data:, vbscript:).
  sanitized = replaceUntilStable(sanitized, /javascript\s*:/gi, "");
  sanitized = replaceUntilStable(sanitized, /data\s*:/gi, "");
  sanitized = replaceUntilStable(sanitized, /vbscript\s*:/gi, "");

  const dimensions = extractSvgDimensionsFromString(sanitized);
  if (dimensions) {
    if (
      dimensions.width < DEFAULT_ICON_CONFIG.minDimensionsPx.width ||
      dimensions.height < DEFAULT_ICON_CONFIG.minDimensionsPx.height
    ) {
      throw new Error(
        `Icon validation failed: SVG dimensions (${dimensions.width}x${dimensions.height}) are below minimum (${DEFAULT_ICON_CONFIG.minDimensionsPx.width}x${DEFAULT_ICON_CONFIG.minDimensionsPx.height})`,
      );
    }

    if (
      dimensions.width > DEFAULT_ICON_CONFIG.maxDimensionsPx.width ||
      dimensions.height > DEFAULT_ICON_CONFIG.maxDimensionsPx.height
    ) {
      throw new Error(
        `Icon validation failed: SVG dimensions (${dimensions.width}x${dimensions.height}) exceed maximum (${DEFAULT_ICON_CONFIG.maxDimensionsPx.width}x${DEFAULT_ICON_CONFIG.maxDimensionsPx.height})`,
      );
    }
  }

  const sizeBytes = Buffer.byteLength(sanitized, "utf8");
  if (sizeBytes > DEFAULT_ICON_CONFIG.maxFileSizeBytes) {
    throw new Error(
      `Icon validation failed: SVG size (${sizeBytes} bytes) exceeds maximum allowed size (${DEFAULT_ICON_CONFIG.maxFileSizeBytes} bytes)`,
    );
  }

  return sanitized;
}

function makeDeterministicCid(seed: string): string {
  return crypto.createHash("sha256").update(seed).digest("hex").slice(0, 46);
}

function buildMetadata(
  input: VaultMetadataInput,
  iconCid: string,
  createdAt = new Date().toISOString(),
): VaultMetadataPayload {
  return {
    name: requireNonEmpty(input.vaultName, "vaultName"),
    description: requireNonEmpty(input.description, "description"),
    icon: `ipfs://${iconCid}`,
    createdAt,
  };
}

async function uploadSvgToPinata(svg: string, pinataJwt: string): Promise<string> {
  const body = new FormData();
  const svgBlob = new Blob([svg], { type: "image/svg+xml" });
  body.append("file", svgBlob, "vault-icon.svg");

  const response = await fetch(PINATA_FILE_API, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${pinataJwt}`,
    },
    body,
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`Pinata SVG upload failed: ${response.status} ${text}`);
  }

  const data = (await response.json()) as { IpfsHash?: string };
  if (!data.IpfsHash) {
    throw new Error("Pinata SVG upload did not return IpfsHash");
  }

  return data.IpfsHash;
}

async function uploadJsonToPinata(
  metadata: VaultMetadataPayload,
  pinataJwt: string,
): Promise<string> {
  const response = await fetch(PINATA_JSON_API, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${pinataJwt}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      pinataContent: metadata,
    }),
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`Pinata metadata upload failed: ${response.status} ${text}`);
  }

  const data = (await response.json()) as { IpfsHash?: string };
  if (!data.IpfsHash) {
    throw new Error("Pinata metadata upload did not return IpfsHash");
  }

  return data.IpfsHash;
}

export function validateVaultMetadataInput(input: unknown): { ok: true } | { ok: false; errors: string[] } {
  const errors: string[] = [];

  if (!input || typeof input !== 'object') {
    errors.push('Input must be a non-null object');
    return { ok: false, errors };
  }

  const data = input as Record<string, unknown>;

  if (!data.vaultName || (typeof data.vaultName === 'string' && data.vaultName.trim() === '')) {
    errors.push('vaultName is required');
  }
  if (!data.description || (typeof data.description === 'string' && data.description.trim() === '')) {
    errors.push('description is required');
  }
  if (!data.iconSvg || (typeof data.iconSvg === 'string' && data.iconSvg.trim() === '')) {
    errors.push('iconSvg is required');
  } else if (typeof data.iconSvg === 'string' && !/<svg[\s\S]*?>/i.test(data.iconSvg)) {
    errors.push('iconSvg must be a valid SVG string');
  }

  if (errors.length > 0) {
    return { ok: false, errors };
  }
  return { ok: true };
}

export async function uploadVaultMetadata(
  input: VaultMetadataInput,
): Promise<UploadVaultMetadataResult> {
  const sanitizedSvg = sanitizeSvg(input.iconSvg);
  const pinataJwt = process.env.PINATA_JWT?.trim();

  if (!pinataJwt) {
    const iconCid = makeDeterministicCid(`icon:${sanitizedSvg}`);
    const metadata = buildMetadata(input, iconCid, "1970-01-01T00:00:00.000Z");
    const metadataCid = makeDeterministicCid(
      `meta:${JSON.stringify(metadata)}:${sanitizedSvg}`,
    );

    return {
      cid: metadataCid,
      metadataUri: `ipfs://${metadataCid}`,
      iconUri: `ipfs://${iconCid}`,
      metadata,
      uploadMode: "local-fallback",
    };
  }

  const iconCid = await uploadSvgToPinata(sanitizedSvg, pinataJwt);
  const metadata = buildMetadata(input, iconCid);
  const metadataCid = await uploadJsonToPinata(metadata, pinataJwt);

  return {
    cid: metadataCid,
    metadataUri: `ipfs://${metadataCid}`,
    iconUri: `ipfs://${iconCid}`,
    metadata,
    uploadMode: "pinata",
  };
}

// ── Relayer Status Service ─────────────────────────────────────────────────
// Tracks bridge relayer health metrics: queue depth, replay protection,
// relay failures, and recent activity for the read-only status page.

export interface RelayEvent {
  id: string;
  timestamp: string;
  status: "success" | "failed" | "pending";
  innerTxHash?: string;
  feeBumpHash?: string;
  error?: string;
  durationMs: number;
}

export interface ReplayProtectionStatus {
  enabled: boolean;
  trackedHashes: number;
  oldestHashAge: string | null;
  deduplicationWindow: string;
}

export interface RelayerStatus {
  isOnline: boolean;
  network: string;
  queueDepth: number;
  totalRelayed: number;
  successCount: number;
  failureCount: number;
  successRate: number; // 0-100
  avgDurationMs: number;
  lastRelayAt: string | null;
  recentEvents: RelayEvent[];
  replayProtection: ReplayProtectionStatus;
  uptime: string;
  checkedAt: string;
}

// ── In-memory state ───────────────────────────────────────────────────────

const MAX_EVENTS = 100;
const DEDUP_WINDOW_HOURS = 24;

const events: RelayEvent[] = [];
const seenHashes = new Map<string, number>(); // hash -> timestamp ms
const startedAt = Date.now();

let pendingCount = 0;

// ── Public API ────────────────────────────────────────────────────────────

export function recordRelayStart(): string {
  const id = `relay_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
  pendingCount++;
  return id;
}

export function recordRelaySuccess(
  id: string,
  durationMs: number,
  innerTxHash?: string,
  feeBumpHash?: string,
): void {
  pendingCount = Math.max(0, pendingCount - 1);

  if (innerTxHash) {
    seenHashes.set(innerTxHash, Date.now());
  }
  if (feeBumpHash) {
    seenHashes.set(feeBumpHash, Date.now());
  }

  events.unshift({
    id,
    timestamp: new Date().toISOString(),
    status: "success",
    innerTxHash,
    feeBumpHash,
    durationMs,
  });

  if (events.length > MAX_EVENTS) events.length = MAX_EVENTS;
  pruneSeenHashes();
}

export function recordRelayFailure(id: string, durationMs: number, error: string): void {
  pendingCount = Math.max(0, pendingCount - 1);

  events.unshift({
    id,
    timestamp: new Date().toISOString(),
    status: "failed",
    error,
    durationMs,
  });

  if (events.length > MAX_EVENTS) events.length = MAX_EVENTS;
}

export function isHashSeen(hash: string): boolean {
  return seenHashes.has(hash);
}

export function getRelayerStatus(): RelayerStatus {
  pruneSeenHashes();

  const successCount = events.filter((e) => e.status === "success").length;
  const failureCount = events.filter((e) => e.status === "failed").length;
  const totalRelayed = successCount + failureCount;
  const successRate = totalRelayed > 0 ? Math.round((successCount / totalRelayed) * 100) : 100;

  const durations = events
    .filter((e) => e.status === "success")
    .map((e) => e.durationMs);
  const avgDurationMs =
    durations.length > 0
      ? Math.round(durations.reduce((a, b) => a + b, 0) / durations.length)
      : 0;

  const lastRelayAt = events.length > 0 ? events[0].timestamp : null;

  // Uptime since service started
  const uptimeMs = Date.now() - startedAt;
  const uptimeHours = Math.floor(uptimeMs / (1000 * 60 * 60));
  const uptimeMinutes = Math.floor((uptimeMs % (1000 * 60 * 60)) / (1000 * 60));

  // Replay protection
  const now = Date.now();
  const cutoff = now - DEDUP_WINDOW_HOURS * 60 * 60 * 1000;
  let oldestHashAge: string | null = null;
  let oldestTs = now;

  for (const [, ts] of seenHashes) {
    if (ts < oldestTs) oldestTs = ts;
  }

  if (seenHashes.size > 0) {
    const ageMs = now - oldestTs;
    const ageMinutes = Math.floor(ageMs / (1000 * 60));
    oldestHashAge = ageMinutes < 60 ? `${ageMinutes}m` : `${Math.floor(ageMinutes / 60)}h ${ageMinutes % 60}m`;
  }

  return {
    isOnline: true,
    network: process.env.NETWORK_PASSPHRASE?.includes("TESTNET") ? "testnet" : "mainnet",
    queueDepth: pendingCount,
    totalRelayed,
    successCount,
    failureCount,
    successRate,
    avgDurationMs,
    lastRelayAt,
    recentEvents: events.slice(0, 20),
    replayProtection: {
      enabled: true,
      trackedHashes: seenHashes.size,
      oldestHashAge,
      deduplicationWindow: `${DEDUP_WINDOW_HOURS}h`,
    },
    uptime: `${uptimeHours}h ${uptimeMinutes}m`,
    checkedAt: new Date().toISOString(),
  };
}

// ── Internal ──────────────────────────────────────────────────────────────

function pruneSeenHashes(): void {
  const cutoff = Date.now() - DEDUP_WINDOW_HOURS * 60 * 60 * 1000;
  for (const [hash, ts] of seenHashes) {
    if (ts < cutoff) seenHashes.delete(hash);
  }
}

import NodeCache from "node-cache";
import { freezeService } from "./freezeService";
import {
  strategyStateTransitionAuditService,
  type StrategyLifecycleState,
} from "./strategyStateTransitionAuditService";
import { evaluateHealthScoreChange } from "./healthScoreChangeAlertService";

// ── Types ───────────────────────────────────────────────────────────────

export interface HealthSignal {
  source: 'contract' | 'backend' | 'monitoring' | 'market';
  metric: string;
  value: number;
  weight: number;
  threshold: {
    critical: number;
    warning: number;
    good: number;
  };
  timestamp: string;
  reliability: number; // 0-1
}

export interface StrategyHealthMetrics {
  contractSafety: number; // 0-1
  dataFreshness: number; // 0-1
  providerUptime: number; // 0-1
  liquidityConditions: number; // 0-1
  executionOutcomes: number; // 0-1
  volatilityIndex: number; // 0-1
  errorRate: number; // 0-1
  latency: number; // milliseconds
}

export interface StrategyHealthScore {
  strategyId: string;
  strategyName: string;
  overallScore: number; // 0-100
  metrics: StrategyHealthMetrics;
  status: 'healthy' | 'degraded' | 'critical' | 'disabled';
  signals: HealthSignal[];
  lastUpdated: string;
  trend: 'improving' | 'stable' | 'declining';
  recommendations: string[];
  suppressUntil?: string;
}

export interface HealthThresholds {
  healthy: number;
  degraded: number;
  critical: number;
  disableThreshold: number;
}

export interface HealthConfig {
  scoreUpdateIntervalMinutes: number;
  trendWindowHours: number;
  signalReliabilityThreshold: number;
  autoDisableThreshold: number;
  suppressDurationHours: number;
  cacheResultsMinutes: number;
}

// ── Configuration ───────────────────────────────────────────────────────

const DEFAULT_CONFIG: HealthConfig = {
  scoreUpdateIntervalMinutes: 5,
  trendWindowHours: 24,
  signalReliabilityThreshold: 0.7,
  autoDisableThreshold: 25,
  suppressDurationHours: 6,
  cacheResultsMinutes: 10,
};

const DEFAULT_THRESHOLDS: HealthThresholds = {
  healthy: 80,
  degraded: 60,
  critical: 40,
  disableThreshold: 25,
};

const cache = new NodeCache({
  stdTTL: DEFAULT_CONFIG.cacheResultsMinutes * 60,
  checkperiod: 60,
  useClones: false,
});

// ── Health Score Engine ─────────────────────────────────────────────────

export class StrategyHealthEngine {
  private config: HealthConfig;
  private thresholds: HealthThresholds;
  private historicalScores: Map<string, StrategyHealthScore[]>;

  constructor(config: Partial<HealthConfig> = {}, thresholds: Partial<HealthThresholds> = {}) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.thresholds = { ...DEFAULT_THRESHOLDS, ...thresholds };
    this.historicalScores = new Map();
  }

  /**
   * Calculate health score for a strategy
   */
  async calculateHealthScore(strategyId: string, strategyName: string): Promise<StrategyHealthScore> {
    const cacheKey = `health:${strategyId}`;
    const cached = cache.get<StrategyHealthScore>(cacheKey);

    if (cached && !this.isScoreStale(cached.lastUpdated)) {
      return cached;
    }

    if (freezeService.isFrozen()) {
      throw new Error("Health service is frozen");
    }

    try {
      // Collect health signals from all sources
      const signals = await this.collectHealthSignals(strategyId);

      // Calculate individual metrics
      const metrics = this.calculateMetrics(signals);

      // Calculate overall score
      const overallScore = this.calculateOverallScore(metrics, signals);

      // Determine status
      const status = this.determineHealthStatus(overallScore, metrics);

      // Map health status + freeze flag into lifecycle state for audit graph.
      const lifecycleState: StrategyLifecycleState = freezeService.isFrozen(strategyId)
        ? "frozen"
        : status === "healthy"
          ? "healthy"
          : "degraded";

      // #371 append-only lifecycle transition audit (must never block health rendering).
      try {
        strategyStateTransitionAuditService.updateFromHealth(
          strategyId,
          lifecycleState,
          `health_status=${status}`,
        );
      } catch (err) {
        console.warn(
          `Failed to record lifecycle transition for ${strategyId}:`,
          err instanceof Error ? err.message : String(err),
        );
      }

      // Analyze trend
      const trend = this.analyzeTrend(strategyId, overallScore);

      // Generate recommendations
      const recommendations = this.generateRecommendations(status, metrics, signals);

      // Check suppression status
      const suppressUntil = this.checkSuppressionStatus(strategyId);

      const healthScore: StrategyHealthScore = {
        strategyId,
        strategyName,
        overallScore,
        metrics,
        status,
        signals,
        lastUpdated: new Date().toISOString(),
        trend,
        recommendations,
        suppressUntil,
      };

      // Update historical data
      this.updateHistoricalScores(strategyId, healthScore);

      // Cache the result
      cache.set(cacheKey, healthScore);

      // Evaluate health score change for alert dispatch (#527)
      try {
        evaluateHealthScoreChange(healthScore);
      } catch (err) {
        console.warn(
          `Failed to evaluate health score change for ${strategyId}:`,
          err instanceof Error ? err.message : String(err),
        );
      }

      // Auto-disable if necessary
      if (overallScore < this.config.autoDisableThreshold && !suppressUntil) {
        await this.handleAutoDisable(strategyId, healthScore);
      }

      return healthScore;
    } catch (error) {
      console.error(`Failed to calculate health score for ${strategyId}:`, error);

      // Return degraded score on error
      return {
        strategyId,
        strategyName,
        overallScore: 0,
        metrics: this.getDefaultMetrics(),
        status: 'critical',
        signals: [],
        lastUpdated: new Date().toISOString(),
        trend: 'declining',
        recommendations: ['Manual investigation required - health check failed'],
      };
    }
  }

  /**
   * Collect health signals from all sources
   */
  private async collectHealthSignals(strategyId: string): Promise<HealthSignal[]> {
    const signals: HealthSignal[] = [];

    try {
      // Contract safety signals
      const contractSignals = await this.getContractSafetySignals(strategyId);
      signals.push(...contractSignals);

      // Backend signals
      const backendSignals = await this.getBackendSignals(strategyId);
      signals.push(...backendSignals);

      // Monitoring signals
      const monitoringSignals = await this.getMonitoringSignals(strategyId);
      signals.push(...monitoringSignals);

      // Market signals
      const marketSignals = await this.getMarketSignals(strategyId);
      signals.push(...marketSignals);

    } catch (error) {
      console.error(`Failed to collect signals for ${strategyId}:`, error);
    }

    // Filter by reliability threshold
    return signals.filter(signal => signal.reliability >= this.config.signalReliabilityThreshold);
  }

  /**
   * Calculate individual metrics from signals
   */
  private calculateMetrics(signals: HealthSignal[]): StrategyHealthMetrics {
    const contractSafetySignals = signals.filter(s => s.source === 'contract');
    const dataFreshnessSignals = signals.filter(s => s.source === 'backend');
    const providerUptimeSignals = signals.filter(s => s.source === 'backend');
    const liquiditySignals = signals.filter(s => s.source === 'market');
    const executionSignals = signals.filter(s => s.source === 'monitoring');

    return {
      contractSafety: this.calculateMetricScore(contractSafetySignals),
      dataFreshness: this.calculateMetricScore(dataFreshnessSignals),
      providerUptime: this.calculateMetricScore(providerUptimeSignals),
      liquidityConditions: this.calculateMetricScore(liquiditySignals),
      executionOutcomes: this.calculateMetricScore(executionSignals),
      volatilityIndex: Math.min(100, Math.max(0, 100 - (signals.find(s => s.metric === 'volatility')?.value || 0) * 10)),
      errorRate: Math.min(100, Math.max(0, 100 - (signals.find(s => s.metric === 'error_rate')?.value || 0) * 100)),
      latency: Math.min(100, Math.max(0, 100 - (signals.find(s => s.metric === 'latency')?.value || 0) / 10)),
    };
  }

  /**
   * Calculate metric score from signals
   */
  private calculateMetricScore(signals: HealthSignal[]): number {
    if (signals.length === 0) return 50; // Default neutral score

    const weightedSum = signals.reduce((sum, signal) => sum + (signal.value * signal.weight), 0);
    const totalWeight = signals.reduce((sum, signal) => sum + signal.weight, 0);

    return totalWeight > 0 ? Math.round(weightedSum / totalWeight) : 50;
  }

  /**
   * Calculate overall score from metrics
   */
  private calculateOverallScore(metrics: StrategyHealthMetrics, signals: HealthSignal[]): number {
    const weights = {
      contractSafety: 0.25,
      dataFreshness: 0.15,
      providerUptime: 0.20,
      liquidityConditions: 0.15,
      executionOutcomes: 0.15,
      volatilityIndex: 0.05,
      errorRate: 0.03,
      latency: 0.02,
    };

    const score = Object.entries(weights).reduce((sum, [key, weight]) => {
      const metricValue = metrics[key as keyof StrategyHealthMetrics];
      return sum + (metricValue * weight);
    }, 0);

    return Math.round(Math.min(100, Math.max(0, score)));
  }

  /**
   * Determine health status from score and metrics
   */
  private determineHealthStatus(overallScore: number, metrics: StrategyHealthMetrics): "healthy" | "degraded" | "critical" | "disabled" {
    if (overallScore >= 80 && metrics.contractSafety >= 70) return 'healthy';
    if (overallScore >= 60 && metrics.contractSafety >= 50) return 'degraded';
    return 'critical';
  }

